// ------------------------------------------------------------
//  Move the Coins – solution in C (GNU‑C17)
// ------------------------------------------------------------
#include <bits/stdc++.h>
using namespace std;

const long long MOD = 1000000007LL;

// ---------- Fenwick tree ----------
struct Fenwick {
    int n; vector<int> bit;
    Fenwick(int n=0){init(n);}    
    void init(int n_){n=n_; bit.assign(n+1,0);}    
    void add(int idx,int val){for(;idx<=n;idx+=idx&-idx) bit[idx]+=val;}
    int sumPrefix(int idx){int s=0; for(;idx>0;idx-=idx&-idx) s+=bit[idx]; return s;}
    // smallest index such that prefix sum >= k (1‑based). assumes k is valid
    int kth(int k){int idx=0, mask=1; while(mask<<1 <= n) mask<<=1; // highest power of two <= n
        for(;mask;mask>>=1){int nxt=idx+mask; if(nxt<=n && bit[nxt]<k){idx=nxt; k-=bit[nxt];}}
        return idx+1; // 1‑based index
    }
};

int N, Q;
vector<vector<int>> adj;
vector<int> depth, parent, subSize;
vector<int> tin, tout; int timerDFS;

void dfs(int v,int p){
    parent[v]=p; tin[v]=++timerDFS; subSize[v]=1;
    for(int to:adj[v]) if(to!=p){
        depth[to]=depth[v]+1; dfs(to,v); subSize[v]+=subSize[to];
    }
    tout[v]=timerDFS;
}

bool isAncestor(int u,int v){ // u is ancestor of v?
    return tin[u]<=tin[v] && tout[v]<=tout[u];
}

// lazy vectors for each possible u (2..N)
vector<vector<int>> vec; // stores admissible v sorted by (depth, id)
vector<int> posPtr; // how many elements already removed from the front

// build vector for a given u on first use
void buildVec(int u){
    if(!vec[u].empty()) return; // already built
    vec[u].reserve(N - subSize[u]);
    for(int v=1; v<=N; ++v){
        if(v==u) continue;
        if(isAncestor(u,v)) continue; // v inside subtree of u -> not allowed
        vec[u].push_back(v);
    }
    sort(vec[u].begin(), vec[u].end(), [&](int a,int b){
        if(depth[a]!=depth[b]) return depth[a]<depth[b];
        return a<b;
    });
    posPtr[u]=0;
}

long long modPow(long long base,long long exp){
    long long res=1%MOD; base%=MOD;
    while(exp){ if(exp&1) res=res*base%MOD; base=base*base%MOD; exp>>=1; }
    return res;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        cin>>N;
        adj.assign(N+1, {});
        for(int i=0;i<N-1;++i){int a,b;cin>>a>>b;adj[a].push_back(b);adj[b].push_back(a);}        
        depth.assign(N+1,0);
        parent.assign(N+1,0);
        subSize.assign(N+1,0);
        tin.assign(N+1,0); tout.assign(N+1,0); timerDFS=0;
        dfs(1,0);
        // initialise structures for u = 2..N
        vec.assign(N+1, {});
        posPtr.assign(N+1,0);
        Fenwick fen(N);
        for(int u=2; u<=N; ++u){
            int sz = N - subSize[u]; // number of admissible v for this u
            fen.add(u, sz);
        }
        cin>>Q;
        long long d=0;
        for(int i=1;i<=Q;++i){
            long long e;cin>>e;
            long long c = (e ^ d); // decrypted index (1‑based)
            // find u such that prefix sum >= c
            int u = fen.kth((int)c);
            // ensure vector for u is built
            buildVec(u);
            int idxInGroup = (int)(c - fen.sumPrefix(u-1)); // 1‑based inside group
            int realIdx = posPtr[u] + idxInGroup - 1; // 0‑based index in vec[u]
            int v = vec[u][realIdx];
            // update decryption key
            long long add = (modPow(2,i)*u + modPow(3,i)*v) % MOD;
            d = (d + add) % MOD;
            // delete the chosen element: we simply move the pointer forward
            posPtr[u]++;
            fen.add(u, -1); // one less element in this group
        }
        cout<<d<<"\n";
    }
    return 0;
}
